#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        long long dp[N + 1][K];
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j < K; j++) {
                dp[i][j] = 0;
            }
        }
        for (int i = 1; i <= N; i++) {
            for (int j = 0; j < K; j++) {
                if (i == 1) {
                    dp[i][j] = 1;
                } else {
                    for (int k = 0; k < K; k++) {
                        if (k != j) {
                            dp[i][j] = (dp[i][j] + dp[i - 1][k]) % MOD;
                        }
                    }
                }
            }
        }
        long long ans = 0;
        for (int i = 1; i <= N; i++) {
            for (int j = 0; j < K; j++) {
                ans = (ans + dp[i][j]) % MOD;
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

