code.JavaScript:
const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const MOD = 1000000007;
const T = parseInt(lines[idx++]);
for (let i = 0; i < T; i++) {
    const [N, K] = lines[idx++].trim().split(' ').map(Number);
    const dp = Array(N + 1).fill(0).map(() => Array(K).fill(0));
    for (let j = 1; j <= N; j++) {
        for (let k = 0; k < K; k++) {
            if (j === 1) {
                dp[j][k] = 1;
            } else {
                for (let l = 0; l < K; l++) {
                    if (l !== k) {
                        dp[j][k] = (dp[j][k] + dp[j - 1][l]) % MOD;
                    }
                }
            }
        }
    }
    let ans = 0;
    for (let j = 1; j <= N; j++) {
        for (let k = 0; k < K; k++) {
            ans = (ans + dp[j][k]) % MOD;
        }
    }
    console.log(ans);
}

